mapper.nql:
MATCH (v:`${tx.objectTagName}`)
WHERE v.`${tx.objectTagName}`.NAME == '${tx.objectName}'
RETURN v;

MATCH (v:`${tx.subjectTagName}`)
WHERE v.`${tx.subjectTagName}`.NAME == '${tx.subjectName}'
RETURN v;

MATCH (v:`${tx.objectTagName}`)
WHERE id(v) == '${tx.objectId}'
RETURN v;

MATCH (v:`${tx.subjectTagName}`)
WHERE id(v) == '${tx.subjectId}'
RETURN v;

MATCH (v
${ isEmpty( er.subjectTagName ) ? '' : ( ':' + er.subjectTagName ) })-[e:`${er.edgeName}`]->(v1
${ isEmpty( er.objectTagName ) ? '' : ( ':' + er.objectTagName ) })
WHERE 1 == 1
@if ( isNotEmpty( er.subjectName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${er.subjectName}')
OR lower(properties(v1).NAME) CONTAINS lower('${er.subjectName}')
@}
RETURN e;

MATCH (v)-[e]->(v1)
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
RETURN COUNT(e) AS count;

MATCH (v ${ isEmpty( er.subjectTagName ) ? '' : ( ':' + er.subjectTagName ) })-[e]->(v1
${ isEmpty( er.objectTagName ) ? '' : ( ':' + er.objectTagName ) })
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( er.subjectName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${er.subjectName}')
OR lower(properties(v1).NAME) CONTAINS lower('${er.subjectName}')
@}
RETURN e ,rank(e) as rank ORDER BY rank DESC SKIP ${ er.current } LIMIT ${ er.pageSize };

MATCH (v
${ isEmpty( er.subjectTagName ) ? '' : ( ':' + er.subjectTagName ) })-[e:`${er.edgeName}`]->(v1
${ isEmpty( er.objectTagName ) ? '' : ( ':' + er.objectTagName ) })
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( er.subjectName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${er.subjectName}')
OR lower(properties(v1).NAME) CONTAINS lower('${er.subjectName}')
@}
RETURN e ,rank(e) as rank ORDER BY rank DESC SKIP ${ er.current } LIMIT ${ er.pageSize };

MATCH (v ${ isEmpty( re.subjectTagName ) ? '' : ( ':' + re.subjectTagName ) })-[e]->(v1
${ isEmpty( re.objectTagName ) ? '' : ( ':' + re.objectTagName ) })
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( re.subjectName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${re.subjectName}')
OR lower(properties(v1).NAME) CONTAINS lower('${re.subjectName}')
@}
RETURN count(*) as total;

MATCH (v
${ isEmpty( re.subjectTagName ) ? '' : ( ':' + re.subjectTagName ) })-[e:`${re.edgeName}`]->(v1
${ isEmpty( re.objectTagName ) ? '' : ( ':' + re.objectTagName ) })
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( re.subjectName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${re.subjectName}')
OR lower(properties(v1).NAME) CONTAINS lower('${re.subjectName}')
@}
RETURN count(*) as total;

MATCH (v)-[e:`${ edgeName }`]->(v1)
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
RETURN COUNT(e) AS count;

MATCH (v)-[e]->(v1)
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( entityName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${entityName}')
OR lower(properties(v1).NAME) CONTAINS lower('${entityName}')
@}
@if ( isNotEmpty( subjectTagName ) ) {
AND '${subjectTagName}' in labels(v)
@}
@if ( isNotEmpty( objectTagName ) ) {
AND '${objectTagName}' in labels(v)
@}
RETURN e,properties(v).NAME as name ORDER BY name ASC;

MATCH (v
${ isEmpty( subjectTagName ) ? '' : ( ':' + subjectTagName ) })-[e:`${tagEdgeName}`]->(v1
${ isEmpty( objectTagName ) ? '' : ( ':' + objectTagName ) })
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
@if ( isNotEmpty( entityName ) ) {
AND lower(properties(v).NAME) CONTAINS lower('${entityName}')
OR lower(properties(v1).NAME) CONTAINS lower('${entityName}')
@}
RETURN e,properties(v).NAME as name ORDER BY name ASC ;

MATCH (v1)-[e:`${re.edgeName}`]->(v2)
WHERE id(v1) == "${re.subjectId}" AND id(v2) == "${re.objectId}"
@if ( isNotEmpty( re.attributeMatch ) ) {
AND ${re.attributeMatch}
@}
RETURN properties(e) as e;

MATCH (v)-[e:`${re.edgeName}`]->(v1)
WHERE id(v) == ${re.subjectId} and id(v1) == ${re.objectId}
RETURN e;

MATCH (v)-[e:`${edgeName}`]->(v1)
WHERE 1 == 1 AND properties(v).NAME IS NOT NULL AND properties(v1).NAME IS NOT NULL
RETURN ${propertyName} ;

MATCH (v:${tag})
WHERE v.${tag}.NAME == ${name}
RETURN v;
